(3221, 'Йоргос Кацикас тренируется в Бресте', 'jorgos-katsikas-treniruetsya-v-breste', '<p>Защитник \"Динамо-Брест\" Йоргос Кацикас не примет участия в тренировочном сборе команды в Турции.</p>\r\n', 17, '2020-01-20 15:00:00', 1, 0),
(3220, 'Сергей Игнатович – игрок \"Динамо-Брест\"', 'sergej-ignatovich-igrok-dinamo-brest', '<p>Сергей Игнатович официально стал игроком футбольного клуба \"Динамо-Брест\"</p>\r\n', 18, '2020-01-20 13:00:00', 1, 1),
(3219, 'Успешный старт в Кубке развития 2020', 'uspeshnyj-start-v-kubke-razvitiya-2020', '<p>Вчера в Минске стартовал международный юношеский турнир \"Кубок развития 2020\".</p>\r\n', 14, '2020-01-20 12:22:00', 1, 1),
(3218, 'На сбор в Турцию полетят 22 игрока', 'na-sbor-v-turtsiyu-poletyat-22-igroka', '<p>Главный тренер \"Динамо-Брест\" Сергей Ковальчук определился со списком игроков на УТС в Турции.</p>\r\n', 17, '2020-01-20 06:11:22', 1, 1),
(3217, 'Абонементы на сезон 2020 уже в продаже', 'abonementy-na-sezon-2020-uzhe-v-prodazhe', '<p>С сегодняшнего дня открыта продажа абонементов на домашние матчи «Динамо-Брест» в сезоне-2020!</p>\r\n', 8, '2020-01-17 07:32:15', 1, 1),
(3216, 'Эдуард Сугак возглавил дубль «Динамо-Брест»', 'eduard-sugak-vozglavil-dubl-dinamo-brest', '<p>Эдуард Сугак - главный тренер дублирующего состава «Динамо-Брест»</p>\r\n', 6, '2020-01-16 11:43:01', 1, 1),
(3212, 'Динамо-Брест в сборных', 'dinamo-brest-v-sbornykh', '<p>Шесть&nbsp;футболистов \"Динамо-Брест\" сыграли&nbsp;в октябрьских матчах сборной Беларуси.</p>\r\n', 1, '2019-10-15 07:44:51', 1, 0),
(3211, 'Пять футболистов \"Динамо-Брест\" вызваны в сборную Беларуси', 'pyat-futbolistov-dinamo-brest-vyzvany-v-sbornuyu-belarusi', '<p>Александр Гутор, Олег Веретило, Павел Савицкий и Денис Лаптев вызваны в национальную сборную Беларуси на матчи квалификации чемпионата Европы УЕФА 2020 против сборной Эстонии и Нидерландов. Павел Павлюченко вызван в молодежную сборную Беларуси&nbsp;на матчи квалификации чемпионата Европы УЕФА 2021 против сборных Норвегии и Кипра.</p>\r\n', 1, '2019-10-07 08:04:25', 1, 1),
(3045, 'Евгений Хачериди подписал контракт с Динамо-Брест (Видео)', 'evgenij-khacheridi-podpisal-kontrakt-s-dinamo-brest', '<p>Защитник сборной&nbsp;Украины&nbsp;Евгений&nbsp;Хачериди&nbsp;пополнит состав \"Динамо-Брест\". Контракт начнет действовать с 1 января 2020 года до конца 2021 года.</p>\r\n', 18, '2019-10-23 12:56:52', 1, 1),
(1665, 'Региональный турнир по мини-футболу посвященный памяти О.М. Сыроквашка', 'regionalnyj-turnir-po-mini-futbolu-posvyashchennyj-pamyati-o-m-syrokvashka', '<p>28 декабря пройдёт региональный турнир по мини-футболу&nbsp;среди мальчиков 2010 года рождения и моложе, посвященный памяти Олега Михайловича Сыроквашка.</p>\r\n', 14, '2019-12-24 07:33:26', 1, 1);
